const output = [];
const orders = items[0].json.orders || [];

for (const order of orders) {
  const isUnfulfilled = order.fulfillment_status === null || order.fulfillment_status === 'unfulfilled';
  if (!isUnfulfilled) continue;

  const noteAttrs = order.note_attributes || [];
  const deliveryDateStr = (noteAttrs.find(a => a.name === 'Delivery-Date') || {}).value;
  const orderDateStr    = (noteAttrs.find(a => a.name === 'Order-Date')   || {}).value;

  const today = new Date();
  let passFilter = true; // افتراضياً يدخل

  // ✅ لو في Delivery-Date نطبّق الشرط، لو مش موجود يدخل تلقائيًا
  if (deliveryDateStr && orderDateStr) {
    const deliveryDate = new Date(deliveryDateStr);
    const orderDate = new Date(orderDateStr);
    const diffOrderToDelivery = Math.ceil((deliveryDate - orderDate) / (1000 * 60 * 60 * 24));
    const diffDeliveryToToday = Math.ceil((deliveryDate - today) / (1000 * 60 * 60 * 24));

    passFilter = !(diffOrderToDelivery > 2 && diffDeliveryToToday > 2);
  }

  // ⚠️ لو عنده Delivery-Date بس مافهوش Order-Date → اعتبره صالح
  else if (deliveryDateStr && !orderDateStr) {
    passFilter = true;
  }

  // ⚠️ لو مافهوش Delivery-Date أو Order-Date → اعتبره صالح برضو
  else if (!deliveryDateStr || !orderDateStr) {
    passFilter = true;
  }

  // ⛔ لو الشرط مش متحقق تجاهل الطلب
  if (!passFilter) continue;

  const orderNumber = order.order_number;
  const lineItems   = order.line_items || [];

  for (const item of lineItems) {
    const title = item.title || '';

    // ✅ منطق المارينيتد الصحيح
    const titleText = (title?.toLowerCase() || '');
    const isMarinated = titleText.includes('marinated') && !titleText.includes('unmarinated');
    const marinatedByName = isMarinated ? 'Yes' : 'No';

    // ✅ أضف الـ variant_title
    const variantTitle = item.variant_title || 'Default';

    output.push({
      json: {
        order_number: orderNumber,
        title,
        variant_title: variantTitle,
        grams: item.grams,
        quantity: item.quantity || 1,
        fulfillment_status: order.fulfillment_status,
        product_id: item.product_id,
        marinated: marinatedByName,
        product_type: '',
        collections: 'Loading…'
      }
    });
  }
}

return output;

const grouped = {};

for (const item of items) {
  const data = item.json;
  const fullTitle = data.title || '';
  const variantTitle = data.variant_title || '';
  const productType = data.product_type || '';
  const marinated = data.marinated || '';
  const quantity = Number(data.quantity) || 0;
  const weight = Number(data.total_weight_kg) || 0;

  // 🔢 استخدام عدد القطع المستخرج مسبقاً
  const numOfPieces = Number(data.num_of_pieces) || 0;
  const totalPieces = quantity * numOfPieces;

  // 🍔 معالجة Chicken Burger و Premium Hamburger كمنتجات مفرومة
  const isChickenBurger = /chicken\s*burger/i.test(fullTitle);
  const isPremiumHamburger = /premium\s*hamburger/i.test(fullTitle);

  // 🥩 معالجة Boneless Drumsticks/Thighs
  const isBonelessDrumsticks = /chicken\s*drumsticks.*boneless/i.test(fullTitle);
  const isBonelessThighs = /chicken\s*thighs.*boneless/i.test(fullTitle);
  const isWholeThighsBoneless = /chicken\s*whole\s*thighs.*boneless/i.test(fullTitle);

  // تحديد إذا كان المنتج minced أو kofta
  const isMincedOrKofta = /(minced|kofta)/i.test(fullTitle);

  let key, displayTitle;

  // 🍗 جمع Boneless Drumsticks/Thighs
  if (isBonelessDrumsticks || isBonelessThighs || isWholeThighsBoneless) {
    key = 'boneless_chicken_parts';
    displayTitle = 'Chicken Whole Thighs - Boneless';
  }
  // 🍔 جمع Chicken Burger مع Minced Chicken
  else if (isChickenBurger) {
    key = 'minced_kofta_chicken';
    displayTitle = 'Minced Chicken';
  }
  // 🍔 جمع Premium Hamburger مع Minced Meat
  else if (isPremiumHamburger) {
    key = 'minced_kofta_meat';
    displayTitle = 'Minced Meat';
  }
  // 🥩 جمع Minced/Kofta حسب النوع
  else if (isMincedOrKofta) {
    const typeKey = productType.toLowerCase().includes('chicken') ? 'chicken' : 'meat';
    key = `minced_kofta_${typeKey}`;
    displayTitle = typeKey === 'chicken' ? 'Minced Chicken' : 'Minced Meat';
  }
  // 📦 باقي المنتجات تستخدم الاسم الكامل
  else {
    key = fullTitle.toLowerCase().trim();
    displayTitle = fullTitle.trim();
  }

  // إنشاء المجموعة إذا لم تكن موجودة
  if (!grouped[key]) {
    grouped[key] = {
      title: displayTitle,
      product_type: productType,
      total_weight_kg: 0,
      total_pieces: 0,
      marinated_states: new Set(),
      names: new Set(),
      use_weight_for_display: false // علم خاص لتحديد طريقة العرض
    };
  }

  // 🍔 Chicken Burger و Premium Hamburger يستخدمون الوزن فقط
  if (isChickenBurger || isPremiumHamburger) {
    grouped[key].total_weight_kg += weight;
    grouped[key].use_weight_for_display = true;
  } else {
    grouped[key].total_weight_kg += weight;
    grouped[key].total_pieces += totalPieces;
  }

  grouped[key].marinated_states.add(marinated);
  grouped[key].names.add(fullTitle);
}

// تحويل النتائج النهائية
let results = Object.values(grouped).map(entry => {
  let marinatedFinal = 'No';
  if (entry.marinated_states.has('Yes') && entry.marinated_states.has('No')) {
    marinatedFinal = 'Mixed';
  } else if (entry.marinated_states.has('Yes')) {
    marinatedFinal = 'Yes';
  }

  // تحديد طريقة العرض: وزن أو قطع
  let finalWeightOrPieces;
  if (entry.use_weight_for_display) {
    // المنتجات التي تستخدم الوزن فقط (Burgers)
    finalWeightOrPieces = entry.total_weight_kg.toFixed(2);
  } else if (entry.total_pieces > 0) {
    // المنتجات التي لها قطع
    finalWeightOrPieces = `${entry.total_pieces} ST`;
  } else {
    // المنتجات التي تستخدم الوزن
    finalWeightOrPieces = entry.total_weight_kg.toFixed(2);
  }

  return {
    json: {
      title: entry.title,
      product_type: entry.product_type,
      total_weight_kg: finalWeightOrPieces,
      marinated: marinatedFinal
    }
  };
});

// ترتيب حسب النوع
results.sort((a, b) => {
  return (a.json.product_type || '').localeCompare(b.json.product_type || '');
});

return results;

const grouped = {};

for (const item of items) {
  const data = item.json;

  // ✅ نشتغل فقط على العناصر marinated = Yes
  if (String(data.marinated || '').toLowerCase() !== 'yes') continue;

  const title = data.title || '';
  const variantTitle = data.variant_title || '';
  const quantity = Number(data.quantity) || 0;
  const weight = Number(data.total_weight_kg) || 0;

  // 🧮 استخراج عدد القطع من الـ variant_title (مثلاً "5 Pieces" أو "3 pcs")
  const pieceMatch = variantTitle.match(/(\d+)\s*(?:pieces?|pcs?)/i);
  const piecesPerUnit = pieceMatch ? Number(pieceMatch[1]) : 0;

  // ✅ حساب إجمالي القطع = الكمية × عدد القطع في كل وحدة
  const totalPieces = quantity * piecesPerUnit;

  // 🔹 استخراج اسم الـ Marinade فقط
  let marinadeOnly = variantTitle;

  // أولاً: نقسم على / أو -
  const parts = variantTitle.split(/\s*[\/\-]\s*/);

  // نلاقي الجزء اللي فيه كلمة "Marinade"
  for (const part of parts) {
    if (/marinade/i.test(part)) {
      marinadeOnly = part
        .replace(/^[⭐★✨]\s*/, '') // شيل الرموز من الأول
        .replace(/\s*\([^)]*\)/g, '') // شيل أي حاجة بين أقواس مثل (House Special)
        .replace(/\s*\d+\s*(?:g|kg|piece|pcs|pieces).*/gi, '') // شيل الأوزان والقطع
        .trim();
      break;
    }
  }

  // 🔑 المفتاح = title + variant_title الكامل (للتجميع الصحيح)
  const groupKey = `${title}|||${variantTitle}`;

  // ✅ إنشاء العنصر لو مش موجود
  if (!grouped[groupKey]) {
    grouped[groupKey] = {
      title,
      variant_title: marinadeOnly, // 👈 اسم الـ Marinade بس
      total_weight_kg: 0,
      num_of_pieces: 0,
      quantity_total: 0
    };
  }

  // ✅ لو المنتج فيه قطع → اجمع القطع وخلي الوزن صفر
  if (piecesPerUnit > 0) {
    grouped[groupKey].num_of_pieces += totalPieces;
    grouped[groupKey].total_weight_kg = 0;
  } 
  // ✅ لو مش قطعة → اجمع الوزن عادي
  else {
    grouped[groupKey].total_weight_kg += weight;
  }

  // ✅ اجمع الكمية في كل الحالات
  grouped[groupKey].quantity_total += quantity;
}

// ✅ رجّع الناتج النهائي مرتب حسب اسم المنتج (title)
return Object.values(grouped)
  .sort((a, b) => a.title.localeCompare(b.title)) // 👈 الترتيب الأبجدي
  .map(entry => ({ json: entry }));

// Flatten "items" array so each product gets its own row
const output = [];

for (const entry of items) {
  const orderNumber = entry.json.order_number;
  const itemList = entry.json.items;

  // ✅ Check if itemList is actually an array before looping
  if (Array.isArray(itemList)) {
    for (const item of itemList) {
      output.push({
        json: {
          order_number: orderNumber,
          title: item.title || '',
          variant_title: item.variant_title || '',     // ✅ تمت الإضافة
          grams: item.grams || null,
          quantity: item.quantity || 0,                // ✅ تمت الإضافة
          is_piece: item.is_piece || 'No',             // ✅ تمت الإضافة
          marinated: item.marinated || '',
        },
      });
    }
  } else {
    // ✅ If not an array, push a single entry
    output.push({
      json: {
        order_number: orderNumber,
        title: entry.json.title || '',
        variant_title: entry.json.variant_title || '', // ✅ تمت الإضافة
        grams: entry.json.grams || null,
        quantity: entry.json.quantity || 0,            // ✅ تمت الإضافة
        is_piece: entry.json.is_piece || 'No',         // ✅ تمت الإضافة
        marinated: entry.json.marinated || '',
      },
    });
  }
}

return output;

// Add createdAt field with only the date (YYYY-MM-DD) in German timezone
return items.map(item => {
  // Format date in German time
  let createdAt = new Date()
    .toLocaleDateString('sv-SE', { timeZone: 'Europe/Berlin' })
    .replace(/\s+/g, '') // remove any stray spaces
    .replace(/\n/g, '')  // remove any hidden newlines
    .trim();             // final clean-up

  // Also clean up any existing string fields that could carry \n
  const cleanJson = {};
  for (const [key, value] of Object.entries(item.json)) {
    cleanJson[key] = typeof value === 'string'
      ? value.replace(/\s+/g, ' ').replace(/\n/g, '').trim()
      : value;
  }

  // Add createdAt
  cleanJson.createdAt = createdAt;

  return { json: cleanJson };
});

// For Chef
return items.map(item => {
  item.binary.data.fileName = "Chef_Report.xlsx";
  return item;
});

// For Orders
return items.map(item => {
  item.binary.data.fileName = "Orders_Report.xlsx";
  return item;
});

// Europe/Berlin date, formatted as DD-MM-YYYY (safe for filenames)
const today = new Date()
  .toLocaleDateString('en-GB', { timeZone: 'Europe/Berlin' })
  .replace(/\//g, '-');

// Take the three binaries coming from the Merge node
const f1 = items[0].binary.data;
const f2 = items[1].binary.data;
const f3 = items[2].binary.data;

// Give each one a nice, dated filename
f1.fileName = `Butcher_Report_${today}.xlsx`;
f2.fileName = `Chef_Report_${today}.xlsx`;
f3.fileName = `Orders_Report_${today}.xlsx`;

// Return a single item with 3 binary properties + the date in JSON
return [{
  binary: {
    file1: f1,
    file2: f2,
    file3: f3,
  },
  json: {
    today, // we will use this in the email subject/body
  }
}];

// 🧩 استقبل ناتج الطلبين
const orderItems = $items("Code in JavaScript"); // الطلبات الأصلية
const productDetails = $items("Flatten Products"); // تفاصيل المنتج بعد الفلترة

// ⚖️ دالة لتحويل الجرام إلى كجم
const toKg = grams => grams ? grams / 1000 : 0;

const merged = [];

for (const orderItem of orderItems) {
  const o = orderItem.json;
  const productId = String(o.product_id).trim();

  // 🔍 ابحث عن المنتج المطابق (يغطي كل حالات Shopify ID)
  const product = productDetails.find(p => {
    const rawId = String(p.json.id).trim();
    const cleanProductId = rawId.replace('gid://shopify/Product/', '');
    const orderId = String(o.product_id).trim();
    return (
      cleanProductId === orderId || rawId.endsWith(orderId)
    );
  });

  // 🧾 اربط التفاصيل
  const productType = product?.json.product_type || 'Unknown';
  const collections = product?.json.collections || '';

  // ⚖️ احسب الوزن بالكيلو
  const totalWeightKg = toKg(o.grams * o.quantity);

  // ✅ أضف الـ variant_title
  const variantTitle = o.variant_title || 'Default';

  // 🔢 استخراج عدد القطع من variant_title
  const pieceMatch = variantTitle.match(/(\d+)\s*(?:pieces?|pcs?)/i);
  const numOfPieces = pieceMatch ? Number(pieceMatch[1]) : 0;

  // ✅ تحقق من وجود كلمة "piece"
  const isPiece = variantTitle.toLowerCase().includes('piece') ? 'Yes' : 'No';

  // 🌶️ تحديد حالة التتبيل - ابحث في variant_title عن "Marinade" أو "Marinated"
  // ✅ لكن استثني "Unmarinated"
  let marinated = 'No';
  if (/marinade|marinated/i.test(variantTitle) && !/unmarinated/i.test(variantTitle)) {
    marinated = 'Yes';
  }

  // 📦 أضف الناتج النهائي
  merged.push({
    json: {
      order_number: o.order_number,
      title: o.title,
      variant_title: variantTitle,
      is_piece: isPiece,
      num_of_pieces: numOfPieces,
      grams: o.grams,
      quantity: o.quantity,
      total_weight_kg: totalWeightKg.toFixed(2),
      product_type: productType,
      marinated: marinated,
      fulfillment_status: o.fulfillment_status,
      collections
    }
  });
}

return merged;

const edges = items[0].json.data.products.edges;

return edges.map(e => ({
  json: {
    id: e.node.id.replace("gid://shopify/Product/", ""),
    title: e.node.title,
    product_type: e.node.productType,
    collections: (e.node.collections.edges || [])
      .map(c => c.node.title)
      .join(", ")
  }
}));

