const mergedItems = $input.all().map(i => i.json);

// Split chef items until the first item that contains order_number
const chefItems = [];
const orderItems = [];
const butcherItems = []; // Add butcher items array
let foundOrderStart = false;

for (const item of mergedItems) {
  if (!foundOrderStart && !item.order_number) {
    chefItems.push(item);
  } else {
    foundOrderStart = true;
    orderItems.push(item);
  }
}

// Get ALL butcher items from input 3 (index 2)
const butcherInputs = $input.all();
if (butcherInputs.length > 2) {
  // Get all items from input 3
  const input3Items = $('Group for Butcher').all();
  input3Items.forEach(item => {
    if (item.json) {
      butcherItems.push(item.json);
    }
  });
}

// Limit for token usage control
const chefLimited = chefItems.slice(0, 150);
const orderLimited = orderItems.slice(0, 250);
const butcherLimited = butcherItems.slice(0, 150); // Limit butcher items

return [
  {
    json: {
      chefItems: chefLimited,
      orderItems: orderLimited,
      butcherItems: butcherLimited // Add butcher items to output
    }
  }
];

let aiResponse = $input.item.json.output || $input.item.json.text || "";

const MAX_LENGTH = 3900; // الحد الأقصى

// نضف النص
function cleanText(text) {
    if (!text) return "";
    text = text.replace(/<[^>]+>/g, '');
    text = text.replace(/\*\*([^*]+)\*\*/g, '$1');
    text = text.replace(/\*([^*]+)\*/g, '$1');
    text = text.replace(/__([^_]+)__/g, '$1');
    text = text.replace(/_([^_]+)_/g, '$1');
    text = text.replace(/`([^`]+)`/g, '$1');
    return text.trim();
}

// نضف النص
let cleaned = cleanText(aiResponse);

// لو النص قصير، ارجعه كده
if (cleaned.length <= MAX_LENGTH) {
    return {
        json: {
            text: cleaned
        }
    };
}

// لو النص طويل، قسمه
let messages = [];
let remaining = cleaned;

while (remaining.length > 0) {
    if (remaining.length <= MAX_LENGTH) {
        messages.push(remaining);
        break;
    }

    // جيب آخر سطر قبل الحد الأقصى
    let chunk = remaining.substring(0, MAX_LENGTH);
    let lastNewline = chunk.lastIndexOf('\n');

    if (lastNewline > MAX_LENGTH * 0.5) {
        chunk = remaining.substring(0, lastNewline);
        remaining = remaining.substring(lastNewline + 1);
    } else {
        remaining = remaining.substring(MAX_LENGTH);
    }

    messages.push(chunk);
}

// أضف رقم الجزء
return messages.map((msg, index) => ({
    json: {
        text: `📨 جزء ${index + 1}/${messages.length}\n\n${msg}`
    }
}));
